#include <stdio.h>
#include <stdlib.h>
#include <sys/stat.h>
#include <string.h>
#include <unistd.h>

int main(void) {
    char template[] = "/tmp/kf_XXXXXX";
    char *dir = mkdtemp(template);
    if (!dir) {
        perror("mkdtemp");
        return 1;
    }
    printf("Repertoire cree\n");

    struct stat sb;
    if (stat(dir, &sb) == 0 && S_ISDIR(sb.st_mode)) {
        printf("Est un repertoire : 1\n");
    }
    printf("Longueur nom : %d\n", (int)strlen(dir) > 0 ? 1 : 0);

    rmdir(dir);
    printf("Repertoire supprime\n");
    return 0;
}

