/* == EXEMPLE ================================================
 * Creer un fichier temporaire avec mkstemp()
 * mkstemp() fonctionne comme mkdtemp() mais pour les fichiers.
 * Le template est modifie en place.
 * =========================================================== */
void example_mkstemp(void) {
    char template[] = "/tmp/kf_ex_XXXXXX";
    int fd = mkstemp(template);
    if (fd == -1) { perror("mkstemp"); return; }
    printf("Fichier cree : %s\n", template);
    close(fd);
    unlink(template);
}
